"use client"

import { motion } from "framer-motion"
import { useInView } from "framer-motion"
import { useRef } from "react"
import { Phone, MapPin, Clock } from "lucide-react"

export default function ContactSection() {
  const ref = useRef(null)
  const isInView = useInView(ref, { once: true, margin: "-100px" })

  return (
    <section id="contact" ref={ref} className="py-24 px-4 md:py-32 lg:py-40">
      <div className="mx-auto max-w-7xl">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
          transition={{ duration: 0.8 }}
          className="mb-16 text-center"
        >
          <div className="mx-auto mb-4 h-px w-16 bg-accent" />
          <h2 className="font-serif text-4xl font-medium text-primary md:text-5xl lg:text-6xl">Visit Us</h2>
          <p className="mx-auto mt-6 max-w-2xl text-lg leading-relaxed text-foreground/70">
            We look forward to serving you happiness
          </p>
        </motion.div>

        <div className="grid gap-12 lg:grid-cols-2">
          {/* Map */}
          <motion.div
            initial={{ opacity: 0, x: -30 }}
            animate={isInView ? { opacity: 1, x: 0 } : { opacity: 0, x: -30 }}
            transition={{ duration: 0.8 }}
            className="h-[400px] overflow-hidden bg-secondary lg:h-[500px]"
          >
            <iframe
              src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3912.5!2d75.9!3d11.25!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2zMTHCsDE1JzAwLjAiTiA3NcKwNTQnMDAuMCJF!5e0!3m2!1sen!2sin!4v1234567890"
              width="100%"
              height="100%"
              style={{ border: 0 }}
              allowFullScreen
              loading="lazy"
              referrerPolicy="no-referrer-when-downgrade"
              title="Makkani Restaurant Location"
            />
          </motion.div>

          {/* Contact Details */}
          <motion.div
            initial={{ opacity: 0, x: 30 }}
            animate={isInView ? { opacity: 1, x: 0 } : { opacity: 0, x: 30 }}
            transition={{ duration: 0.8, delay: 0.2 }}
            className="flex flex-col justify-center space-y-10"
          >
            <div className="flex gap-6">
              <div className="flex h-12 w-12 flex-shrink-0 items-center justify-center rounded-full bg-accent/10">
                <MapPin className="h-6 w-6 text-accent" strokeWidth={1.5} />
              </div>
              <div>
                <h3 className="mb-2 font-serif text-xl font-medium text-primary">Location</h3>
                <p className="leading-relaxed text-foreground/70">
                  Opposite Santhi Hospital,
                  <br />
                  Mukkam Road, Omassery,
                  <br />
                  Kozhikode, Kerala – 673572
                </p>
              </div>
            </div>

            <div className="flex gap-6">
              <div className="flex h-12 w-12 flex-shrink-0 items-center justify-center rounded-full bg-accent/10">
                <Phone className="h-6 w-6 text-accent" strokeWidth={1.5} />
              </div>
              <div>
                <h3 className="mb-2 font-serif text-xl font-medium text-primary">Phone</h3>
                <p className="leading-relaxed text-foreground/70">
                  <a href="tel:+917510015001" className="hover:text-accent transition-colors">
                    +91 75100 15001
                  </a>
                  <br />
                  <a href="tel:+919846445784" className="hover:text-accent transition-colors">
                    +91 98464 45784
                  </a>
                </p>
              </div>
            </div>

            <div className="flex gap-6">
              <div className="flex h-12 w-12 flex-shrink-0 items-center justify-center rounded-full bg-accent/10">
                <Clock className="h-6 w-6 text-accent" strokeWidth={1.5} />
              </div>
              <div>
                <h3 className="mb-2 font-serif text-xl font-medium text-primary">Business Hours</h3>
                <p className="leading-relaxed text-foreground/70">
                  7:00 AM – 12:30 AM
                  <br />
                  Open All Days
                </p>
              </div>
            </div>
          </motion.div>
        </div>
      </div>
    </section>
  )
}
